import os
from sqlalchemy import create_engine, text
Engine = None # This will be our engine for database connection 
def dbConnection():  
    global Engine    
    if not Engine :        
        user=os.getenv('DBUSER')         
        password=os.getenv('DBPASSWORD')     
        hostname='localhost:5432'       # default PostgreSQL port is 5432, but it can be changed based on your setup   
        database_name = 'hackathon_db'  
        
        engine_string = f"postgresql://{user}:{password}@{hostname}/{database_name}"     # this string will contain the connection details for our PostgreSQL server 
                                                                                           
        Engine=create_engine(engine_string)      # create an instance of SQLAlchemy's engine  
    return Engine